#!/usr/bin/env node
/**
 * Repair CapApp-SPM/Package.swift files that were generated by `cap sync` on
 * WINDOWS: the Capacitor CLI writes plugin paths with backslashes there, which
 * are invalid escape sequences in Swift string literals — the manifest then
 * fails to compile on the Mac CI (xcodebuild exit 74 at -showBuildSettings).
 * Flips backslashes to forward slashes inside the ..\..\..\node_modules paths.
 * SwiftPM accepts forward slashes on every platform.
 *
 *   node scripts/_fix-spm-manifest-paths.mjs
 *
 * ⚠️ Re-running `npx cap sync ios` / `node scripts/cap-driver.mjs sync ios` ON
 * WINDOWS re-breaks these files — run this fixer again before committing them.
 */
import { readFileSync, writeFileSync } from "node:fs";

const files = [
  "ios-driver/App/CapApp-SPM/Package.swift",
  "ios/App/CapApp-SPM/Package.swift",
];

for (const f of files) {
  const before = readFileSync(f, "utf8");
  // Only touch quoted relative-path strings (they start with ..\ when broken).
  const after = before.replace(/"\.\.[\\][^"]*"/g, (m) => m.replaceAll("\\", "/"));
  writeFileSync(f, after, "utf8");
  console.log(`${f}: ${before === after ? "already clean" : "FIXED backslash paths"}`);
}
